468		private calculateTrendComponent({
469			values,
470			changePoints,
471			startDate,
472			endDate,
473		}: {
474			values: number[];
475			changePoints: number[];
476			startDate: string;
477			endDate: string;
478		}): number[] {
479			const n = values.length;
480			if (n === 0) return [];
481	
482			const dates = this.generateDateRange(startDate, endDate, n);
483	
484			if (changePoints.length === 0) {
485				return MathematicalFunctions.calculateTrend({ values, dates });
486			}
487	
488			const trend = new Array(n).fill(0) as number[];
489			const segments = [0, ...changePoints, n];
490	
491			for (let i = 0; i < segments.length - 1; i++) {
492				const start = segments[i] as unknown as number;
493				const end = segments[i + 1] as unknown as number;
494				const segmentValues = values.slice(start, end);
495				const segmentDates = dates.slice(start, end);
496	
497				if (segmentValues.length > 1) {
498					const segmentTrend = MathematicalFunctions.calculateTrend({
499						values: segmentValues,
500						dates: segmentDates,
501					});
502	
503					for (let j = 0; j < segmentTrend.length; j++) {
504						trend[start + j] = segmentTrend[j] as unknown as number;
505					}
506				} else if (segmentValues.length === 1) {
507					trend[start] = segmentValues[0] as unknown as number;
508				}
509			}
510	
511			return trend;
512		}
