530		private createComprehensiveForecast({
531			yearlyComponent,
532			monthlyComponent,
533			weeklyComponent,
534			quarterlyComponent,
535			trendComponent,
536			smoothedResidualsArr,
537			historicalLength,
538			forecastDays,
539			endDate,
540		}: {
541			yearlyComponent: number[];
542			monthlyComponent: number[];
543			weeklyComponent: number[];
544			quarterlyComponent: number[];
545			trendComponent: number[];
546			smoothedResidualsArr: number[];
547			historicalLength: number;
548			forecastDays: number;
549			endDate: string;
550			purchasesArr: number[];
551		}): {
552			forecastValues: number[];
553			forecastDates: string[];
554			components: {
555				yearly: number[];
556				monthly: number[];
557				weekly: number[];
558				quarterly: number[];
559				trend: number[];
560				residuals: number[];
561			};
562		} {
563			const forecastDates = this.generateFutureDates(endDate, forecastDays);
564	
565			const harmonics = this.getHarmonicsByObservationsCount({
566				observations: historicalLength,
567			});
568	
569			const extendedYearly = this.extendSeasonalComponent(
570				yearlyComponent,
571				365,
572				harmonics,
573				historicalLength,
574				forecastDates,
575				endDate,
576			);
577			const extendedMonthly = this.extendSeasonalComponent(
578				monthlyComponent,
579				30,
580				harmonics,
581				historicalLength,
582				forecastDates,
583				endDate,
584			);
585			const extendedWeekly = this.extendSeasonalComponent(
586				weeklyComponent,
587				7,
588				harmonics,
589				historicalLength,
590				forecastDates,
591				endDate,
592			);
593			const extendedQuarterly = this.extendSeasonalComponent(
594				quarterlyComponent,
595				91,
596				harmonics,
597				historicalLength,
598				forecastDates,
599				endDate,
600			);
601	
602			const extendedResiduals = this.extendResidualsComponent({
603				smoothedResidualsArr,
604				forecastDays,
605				endDate,
606			});
607	
608			const extendedTrend = this.extendTrendComponent(trendComponent, forecastDays);
609	
610			const forecastValues = Array(forecastDays)
611				.fill(0)
612				.map((_, i) => {
613					const yearly = extendedYearly[i] ?? 0;
614					const monthly = extendedMonthly[i] ?? 0;
615					const weekly = extendedWeekly[i] ?? 0;
616					const quarterly = extendedQuarterly[i] ?? 0;
617					const trend = extendedTrend[i] ?? 0;
618					const residual = extendedResiduals[i] ?? 0;
619					const forecastValue = trend + yearly + monthly + weekly + quarterly + residual;
620					return Math.max(0, forecastValue);
621				});
622	
623			return {
624				forecastValues,
625				forecastDates,
626				components: {
627					yearly: extendedYearly,
628					monthly: extendedMonthly,
629					weekly: extendedWeekly,
630					quarterly: extendedQuarterly,
631					trend: extendedTrend,
632					residuals: extendedResiduals,
633				},
634			};
635		}
